import React from 'react';

const STATUS_LABELS = {
  draft: 'Brouillon', soumis: 'Soumis', en_analyse: 'En analyse',
  devis_genere: 'Devis généré', valide: 'Validé', rejete: 'Rejeté',
};

const STATUS_COLORS = {
  draft: '#8b95a8', soumis: '#60a5fa', en_analyse: '#fbbf24',
  devis_genere: '#c4b5fd', valide: '#4DFFB4', rejete: '#ff6680',
};

const RISK_COLORS = {
  Minimal: '#4DFFB4', Faible: '#34d399', Moyen: '#fbbf24',
  'Élevé': '#fb923c', Critique: '#ff4466',
};

export default function ClientOverview({ dossier, onNavigate }) {
  if (!dossier) return null;

  const steps = [
    { key: 'questionnaire', label: 'Questionnaire', icon: 'ti ti-clipboard-list', done: dossier.questionnaire_complete },
    { key: 'documents', label: 'Documents', icon: 'ti ti-file-upload', done: dossier.documents_count > 0 },
    { key: 'devis', label: 'Devis', icon: 'ti ti-file-invoice', done: !!dossier.devis },
  ];

  return (
    <div>
      {/* Dossier Info */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: 16, marginBottom: 24 }}>
        <div className="cli-status-card">
          <div className="cli-status-label">Entreprise</div>
          <div className="cli-status-value" style={{ fontSize: 18 }}>{dossier.company}</div>
        </div>
        <div className="cli-status-card">
          <div className="cli-status-label">Secteur</div>
          <div className="cli-status-value" style={{ fontSize: 18 }}>{dossier.secteur || '—'}</div>
        </div>
        <div className="cli-status-card">
          <div className="cli-status-label">Taille</div>
          <div className="cli-status-value" style={{ fontSize: 18 }}>{dossier.taille || '—'}</div>
        </div>
        <div className="cli-status-card">
          <div className="cli-status-label">Statut dossier</div>
          <div className="cli-status-value" style={{ fontSize: 16, color: STATUS_COLORS[dossier.status] }}>
            {STATUS_LABELS[dossier.status] || dossier.status}
          </div>
        </div>
      </div>

      {/* Score */}
      {dossier.score != null && (
        <div className="cli-score-section">
          <div className="cli-score-big">{dossier.score}</div>
          <div className="cli-score-info">
            <h3>Score de risque cyber</h3>
            <p style={{ color: RISK_COLORS[dossier.niveau_risque] || 'var(--cli-muted)' }}>
              Niveau: <strong>{dossier.niveau_risque}</strong>
            </p>
            <div className="cli-score-bar">
              <div className="cli-score-fill" style={{ width: `${dossier.score}%` }} />
            </div>
          </div>
        </div>
      )}

      {/* Progression */}
      <div className="cli-card" style={{ marginBottom: 24 }}>
        <div className="cli-card-title">Progression</div>
        <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
          {steps.map((s) => (
            <button
              key={s.key}
              onClick={() => onNavigate(s.key)}
              style={{
                flex: '1 1 150px',
                padding: '16px',
                borderRadius: 12,
                border: `1px solid ${s.done ? 'rgba(167,139,250,0.4)' : 'var(--cli-border)'}`,
                background: s.done ? 'var(--cli-accent-dim)' : 'transparent',
                cursor: 'pointer',
                textAlign: 'left',
                display: 'flex',
                alignItems: 'center',
                gap: 12,
              }}
            >
              <i className={s.icon} style={{ fontSize: 22, color: s.done ? 'var(--cli-accent)' : 'var(--cli-muted)' }} />
              <div>
                <div style={{ fontSize: 14, fontWeight: 600, color: s.done ? 'var(--cli-accent)' : 'var(--cli-text)' }}>
                  {s.label}
                </div>
                <div style={{ fontSize: 12, color: 'var(--cli-muted)', marginTop: 2 }}>
                  {s.done ? 'Complété' : 'À compléter'}
                </div>
              </div>
              {s.done && <i className="ti ti-circle-check" style={{ marginLeft: 'auto', color: 'var(--cli-accent)', fontSize: 18 }} />}
            </button>
          ))}
        </div>
      </div>

      {/* Devis résumé si disponible */}
      {dossier.devis && (
        <div className="cli-devis-card">
          <div style={{ fontSize: 12, color: 'var(--cli-muted)', marginBottom: 8 }}>VOTRE DEVIS</div>
          <div className="cli-devis-prime">{dossier.devis.prime?.toLocaleString('fr-FR')} €</div>
          <div className="cli-devis-label">Prime annuelle estimée</div>
          <span className={`cli-badge cli-badge-${dossier.devis.status}`}>{dossier.devis.status}</span>
          {dossier.devis.motif && (
            <div style={{ marginTop: 12, padding: '10px 14px', background: 'rgba(255,68,102,0.08)', borderRadius: 8, fontSize: 13, color: '#ff6680' }}>
              <i className="ti ti-info-circle" style={{ marginRight: 6 }} />
              {dossier.devis.motif}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
